INSERT INTO `bravo_locations` (`id`, `name`, `content`, `slug`, `image_id`, `map_lat`, `map_lng`, `map_zoom`, `status`, `_lft`, `_rgt`, `parent_id`, `create_user`, `update_user`, `deleted_at`, `origin_id`, `lang`, `created_at`, `updated_at`, `banner_image_id`, `trip_ideas`) VALUES
(1, 'Paris', '<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\"><strong>Parigi</strong> &egrave; la&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Capitale (citt&agrave;)\" href=\"https://it.wikipedia.org/wiki/Capitale_(citt%C3%A0)\">capitale</a>&nbsp;e la&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Citt&agrave;\" href=\"https://it.wikipedia.org/wiki/Citt%C3%A0\">citt&agrave;</a>&nbsp;pi&ugrave; popolata della&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Francia\" href=\"https://it.wikipedia.org/wiki/Francia\">Francia</a>, capoluogo della&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Regioni della Francia\" href=\"https://it.wikipedia.org/wiki/Regioni_della_Francia\">regione</a>&nbsp;dell\'<a style=\"color: #0645ad; background: none;\" title=\"&Icirc;le-de-France\" href=\"https://it.wikipedia.org/wiki/%C3%8Ele-de-France\">&Icirc;le-de-France</a>&nbsp;e l\'unico&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Comuni della Francia\" href=\"https://it.wikipedia.org/wiki/Comuni_della_Francia\">comune</a>&nbsp;a essere nello stesso tempo&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Dipartimenti della Francia\" href=\"https://it.wikipedia.org/wiki/Dipartimenti_della_Francia\">dipartimento</a>, secondo la riforma del 1977 e i dettami della&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Legge PML\" href=\"https://it.wikipedia.org/wiki/Legge_PML\">legge PML</a>&nbsp;che espansero i vecchi confini comunali.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">Con una popolazione di 2&nbsp;229&nbsp;095 abitanti &egrave;, dopo&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Berlino\" href=\"https://it.wikipedia.org/wiki/Berlino\">Berlino</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Madrid\" href=\"https://it.wikipedia.org/wiki/Madrid\">Madrid</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Roma\" href=\"https://it.wikipedia.org/wiki/Roma\">Roma</a>&nbsp;e&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Bucarest\" href=\"https://it.wikipedia.org/wiki/Bucarest\">Bucarest</a>, il&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Comuni dell\'Unione europea per popolazione\" href=\"https://it.wikipedia.org/wiki/Comuni_dell%27Unione_europea_per_popolazione\">quinto comune</a>&nbsp;pi&ugrave; popoloso dell\'<a style=\"color: #0645ad; background: none;\" title=\"Unione europea\" href=\"https://it.wikipedia.org/wiki/Unione_europea\">Unione europea</a>&nbsp;e, in considerazione della superficie comunale, possiede una delle pi&ugrave; alte densit&agrave; abitative del mondo. Tuttavia, l\'estensione urbana della capitale francese &egrave; ben pi&ugrave; ampia del suo territorio comunale: la sua&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Area metropolitana di Parigi\" href=\"https://it.wikipedia.org/wiki/Area_metropolitana_di_Parigi\">area metropolitana</a>, detta anche \"Grande Parigi\" (in francese&nbsp;<em>Grand Paris</em>), conta infatti circa 12 milioni di persone.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">La citt&agrave; si trova nel nord della&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Francia\" href=\"https://it.wikipedia.org/wiki/Francia\">Francia</a>, su un\'<a style=\"color: #0645ad; background: none;\" title=\"Meandro\" href=\"https://it.wikipedia.org/wiki/Meandro\">ansa</a>&nbsp;della&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Senna\" href=\"https://it.wikipedia.org/wiki/Senna\">Senna</a>, posizione molto favorevole poich&eacute; fondamentale snodo di trasporti e traffici del&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Europa\" href=\"https://it.wikipedia.org/wiki/Europa\">continente europeo</a>. In effetti, la posizione di Parigi al centro dei principali itinerari commerciali terrestri e fluviali le permise di diventare una delle citt&agrave; pi&ugrave; influenti della Francia a partire dal&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"X secolo\" href=\"https://it.wikipedia.org/wiki/X_secolo\">X secolo</a>, con la costruzione dei palazzi reali, di ricche abbazie e della celebre&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Cattedrale di Notre-Dame\" href=\"https://it.wikipedia.org/wiki/Cattedrale_di_Notre-Dame\">cattedrale di Notre-Dame</a>.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">Lungo tutto il corso della propria storia, Parigi ha saputo influenzare in modo determinante la&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Politica\" href=\"https://it.wikipedia.org/wiki/Politica\">politica</a>, la&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Cultura\" href=\"https://it.wikipedia.org/wiki/Cultura\">cultura</a>, lo stile di vita e l\'<a style=\"color: #0645ad; background: none;\" title=\"Economia\" href=\"https://it.wikipedia.org/wiki/Economia\">economia</a>&nbsp;dell\'intero mondo occidentale. Nel&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"XIII secolo\" href=\"https://it.wikipedia.org/wiki/XIII_secolo\">XIII secolo</a>&nbsp;diede grande impulso alla rinascita delle arti e del sapere grazie alla presenza della prestigiosa Universit&agrave; della&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Sorbona\" href=\"https://it.wikipedia.org/wiki/Sorbona\">Sorbona</a>&nbsp;nel&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Quartiere latino (Parigi)\" href=\"https://it.wikipedia.org/wiki/Quartiere_latino_(Parigi)\">Quartiere latino</a>; nel&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"XIV secolo\" href=\"https://it.wikipedia.org/wiki/XIV_secolo\">XIV secolo</a>&nbsp;divenne una delle pi&ugrave; importanti citt&agrave; del mondo cristiano. Nell\'Et&agrave; moderna la sua influenza continu&ograve; a crescere in tutti i sensi: nella seconda met&agrave; del&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"XVII secolo\" href=\"https://it.wikipedia.org/wiki/XVII_secolo\">XVII secolo</a>&nbsp;fu la capitale della pi&ugrave; grande potenza militare del continente, nel Settecento divenne il cenacolo europeo della cultura e dei \"lumi\", per poi avviarsi nell\'Ottocento a divenire la citt&agrave; dell\'<a style=\"color: #0645ad; background: none;\" title=\"Arte\" href=\"https://it.wikipedia.org/wiki/Arte\">arte</a>, dei piaceri e del divertimento.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">Ereditando la storia di un&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Impero coloniale francese\" href=\"https://it.wikipedia.org/wiki/Impero_coloniale_francese\">impero coloniale</a>&nbsp;estesosi su cinque continenti, Parigi &egrave; considerata come il centro del mondo francofono e ha mantenuto una posizione internazionale di grande rilievo, sia come influente metropoli mondiale, sia come centro culturale, politico ed economico di indiscusso prestigio. Ospita, tra gli altri, il quartier generale dell\'<a style=\"color: #0645ad; background: none;\" title=\"Organizzazione per la cooperazione e lo sviluppo economico\" href=\"https://it.wikipedia.org/wiki/Organizzazione_per_la_cooperazione_e_lo_sviluppo_economico\">OECD</a>, dell\'<a style=\"color: #0645ad; background: none;\" title=\"UNESCO\" href=\"https://it.wikipedia.org/wiki/UNESCO\">UNESCO</a>&nbsp;e dell\'<a style=\"color: #0645ad; background: none;\" title=\"Agenzia spaziale europea\" href=\"https://it.wikipedia.org/wiki/Agenzia_spaziale_europea\">ESA</a>. Secondo stime effettuate dalla CNN, nel 2009<sup class=\"reference\" style=\"line-height: 1; font-size: 0.7rem; white-space: nowrap;\"><a style=\"color: #0645ad; background: none;\" href=\"https://it.wikipedia.org/wiki/Parigi#cite_note-http://money.cnn.com/magazines/fortune/global500/2009/cities/-2\">[2]</a></sup>&nbsp;Parigi era sede di 27 delle aziende&nbsp;<em><a style=\"color: #0645ad; background: none;\" title=\"Fortune Global 500\" href=\"https://it.wikipedia.org/wiki/Fortune_Global_500\">Fortune Global 500</a></em>, davanti a&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Pechino\" href=\"https://it.wikipedia.org/wiki/Pechino\">Pechino</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"New York\" href=\"https://it.wikipedia.org/wiki/New_York\">New York</a>&nbsp;e&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Londra\" href=\"https://it.wikipedia.org/wiki/Londra\">Londra</a>. La presenza in citt&agrave; di una delle pi&ugrave; importanti borse internazionali e le sue numerose attivit&agrave; economiche, politiche e turistiche, fanno di Parigi uno dei principali centri del mondo. La citt&agrave; &egrave; anche un punto di riferimento per gli&nbsp;<a class=\"mw-redirect\" style=\"color: #0645ad; background: none;\" title=\"Stilisti\" href=\"https://it.wikipedia.org/wiki/Stilisti\">stilisti</a>&nbsp;e per la&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Moda\" href=\"https://it.wikipedia.org/wiki/Moda\">moda</a>, essendone considerata una delle&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Capitale della moda\" href=\"https://it.wikipedia.org/wiki/Capitale_della_moda\">capitali mondiali</a>&nbsp;insieme a&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Milano\" href=\"https://it.wikipedia.org/wiki/Milano\">Milano</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Londra\" href=\"https://it.wikipedia.org/wiki/Londra\">Londra</a>&nbsp;e&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"New York\" href=\"https://it.wikipedia.org/wiki/New_York\">New York</a>.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">Scrigno contenente numerosi monumenti dall\'incalcolabile valore storico e artistico, Parigi rappresenta il simbolo stesso della cultura francese e del suo prestigio nel mondo. I turisti spesso le attribuiscono il qualificativo di \"pi&ugrave; romantica citt&agrave; del globo\", titolo derivato dal periodo del&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Secondo Impero francese\" href=\"https://it.wikipedia.org/wiki/Secondo_Impero_francese\">Secondo Impero</a>&nbsp;durante il quale Parigi&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Trasformazione di Parigi sotto il Secondo Impero\" href=\"https://it.wikipedia.org/wiki/Trasformazione_di_Parigi_sotto_il_Secondo_Impero\">fu profondamente trasformata</a>&nbsp;dal&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Barone Haussmann\" href=\"https://it.wikipedia.org/wiki/Barone_Haussmann\">barone Haussmann</a>, guidato dall\'imperatore&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Napoleone III di Francia\" href=\"https://it.wikipedia.org/wiki/Napoleone_III_di_Francia\">Napoleone III</a>&nbsp;che voleva fare della capitale francese la pi&ugrave; bella citt&agrave; d\'<a style=\"color: #0645ad; background: none;\" title=\"Europa\" href=\"https://it.wikipedia.org/wiki/Europa\">Europa</a>. Quella di Parigi fu infatti una delle pi&ugrave; grandi e pi&ugrave; criticate rivoluzioni urbanistiche (visto lo sventramento del cuore storico della citt&agrave;) nella storia dell\'umanit&agrave;. Nel 1989 fu nominata,assieme a Roma&nbsp;<a class=\"mw-redirect\" style=\"color: #0645ad; background: none;\" title=\"Citt&agrave; europea della cultura\" href=\"https://it.wikipedia.org/wiki/Citt%C3%A0_europea_della_cultura\">citt&agrave; europea della cultura</a>.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">La citt&agrave; &egrave; stata sede di ben cinque&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Esposizione universale\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale\">esposizioni universali</a>&nbsp;(<a style=\"color: #0645ad; background: none;\" title=\"Esposizione universale dei prodotti dell\'agricoltura, dell\'industria e delle belle arti di Parigi (1855)\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale_dei_prodotti_dell%27agricoltura,_dell%27industria_e_delle_belle_arti_di_Parigi_(1855)\">1855</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Esposizione universale di Parigi (1867)\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale_di_Parigi_(1867)\">1867</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Esposizioni universali di Parigi\" href=\"https://it.wikipedia.org/wiki/Esposizioni_universali_di_Parigi\">1878</a>,&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Esposizione universale di Parigi (1889)\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale_di_Parigi_(1889)\">1889</a>&nbsp;e&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Esposizione di Parigi (1900)\" href=\"https://it.wikipedia.org/wiki/Esposizione_di_Parigi_(1900)\">1900</a>), pi&ugrave; di qualunque altra citt&agrave;, che ne hanno in parte modellato l\'aspetto nel&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"XX secolo\" href=\"https://it.wikipedia.org/wiki/XX_secolo\">XX secolo</a>&nbsp;e ha ospitato due edizioni dei&nbsp;<a class=\"mw-redirect\" style=\"color: #0645ad; background: none;\" title=\"Giochi Olimpici\" href=\"https://it.wikipedia.org/wiki/Giochi_Olimpici\">Giochi Olimpici</a>&nbsp;(<a style=\"color: #0645ad; background: none;\" title=\"Giochi della II Olimpiade\" href=\"https://it.wikipedia.org/wiki/Giochi_della_II_Olimpiade\">1900</a>&nbsp;e&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Giochi della VIII Olimpiade\" href=\"https://it.wikipedia.org/wiki/Giochi_della_VIII_Olimpiade\">1924</a>) e ospiter&agrave; l\'edizione dei giochi del&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Giochi della XXXIII Olimpiade\" href=\"https://it.wikipedia.org/wiki/Giochi_della_XXXIII_Olimpiade\">2024</a>.</p>\r\n<p style=\"margin: 0.5em 0px; color: #202122; font-family: sans-serif; font-size: 14px; background-color: #ffffff;\">Uno studio dell\'Institut d\'am&eacute;nagement et d\'urbanisme (IAU) pubblicato nel 2019 sottolinea che i prezzi degli alloggi spingono i nuclei familiari a basso reddito a lasciare Parigi per stabilirsi nei dipartimenti vicini come&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Senna-Saint-Denis\" href=\"https://it.wikipedia.org/wiki/Senna-Saint-Denis\">Senna-Saint-Denis</a>, il che tende a provocare una \"<a style=\"color: #0645ad; background: none;\" title=\"Gentrificazione\" href=\"https://it.wikipedia.org/wiki/Gentrificazione\">gentrificazione</a>\" della capitale e una pauperizzazione dei dipartimenti vicini.<sup class=\"reference\" style=\"line-height: 1; font-size: 0.7rem; white-space: nowrap;\"><a style=\"color: #0645ad; background: none;\" href=\"https://it.wikipedia.org/wiki/Parigi#cite_note-3\">[3]</a></sup>&nbsp;Secondo il sito money.it, nel 2020, Parigi &egrave; la citt&agrave; pi&ugrave; cara al mondo assieme a&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Hong Kong\" href=\"https://it.wikipedia.org/wiki/Hong_Kong\">Hong Kong</a>&nbsp;e&nbsp;<a style=\"color: #0645ad; background: none;\" title=\"Zurigo\" href=\"https://it.wikipedia.org/wiki/Zurigo\">Zurigo</a>.<sup class=\"reference\" style=\"line-height: 1; font-size: 0.7rem; white-space: nowrap;\"><a style=\"color: #0645ad; background: none;\" href=\"https://it.wikipedia.org/wiki/Parigi#cite_note-4\">[4]</a></sup></p>', 'paris', 250, '48.856613', '2.352222', 12, 'publish', 1, 2, NULL, 1, 11, NULL, NULL, NULL, '2023-07-18 01:03:17', '2023-11-05 00:12:43', 112, '[{\"image_id\":\"113\",\"title\":\"Experiencing the best jazz in Harlem, birthplace of bebop\",\"link\":\"#\",\"content\":\"New Orleans might be the home of jazz, but New York City is where many of the genre\\u2019s greats became stars \\u2013 and Harlem was at the heart of it.The neighborhood experienced a rebirth during the...\"},{\"image_id\":\"114\",\"title\":\"Reflections from the road: transformative \\u2018Big Trip\\u2019 experiences\",\"link\":\"#\",\"content\":\"Whether it\\u2019s a gap year after finishing school, a well-earned sabbatical from work or an overseas adventure in celebration of your retirement, a big trip is a rite of passage for every traveller, with myriad life lessons to be ...\"},{\"image_id\":\"249\",\"title\":\"LOUVRE\",\"link\":\"https:\\/\\/www.louvre.fr\\/en\",\"content\":\"There are plenty of good reasons to visit the Louvre! So many works of art to discover in this fabulous museum that used to be a palace!\"}]'),
