INSERT INTO `bravo_location_translations` (`id`, `origin_id`, `locale`, `name`, `content`, `create_user`, `update_user`, `created_at`, `updated_at`, `trip_ideas`) VALUES
(1, 11, 'id', 'Bali', '<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\"><strong>Bali</strong> (juga dikenal sebagai <strong>Kepulauan Bali</strong>, <a style=\"color:#3366cc;background:none;\" title=\"Bahasa Bali\" href=\"https://id.wikipedia.org/wiki/Bahasa_Bali\">Bali</a>: <span lang=\"ban\" xml:lang=\"ban\">ᬩᬮᬶ</span>) adalah sebuah wilayah <a style=\"color:#3366cc;background:none;\" title=\"Provinsi\" href=\"https://id.wikipedia.org/wiki/Provinsi\">provinsi</a> yang terletak di <a style=\"color:#3366cc;background:none;\" title=\"Indonesia\" href=\"https://id.wikipedia.org/wiki/Indonesia\">Indonesia</a>. Ibu kotanya adalah <a style=\"color:#3366cc;background:none;\" title=\"Kota Denpasar\" href=\"https://id.wikipedia.org/wiki/Kota_Denpasar\">Denpasar</a>. Provinsi Bali terletak di bagian barat <a style=\"color:#3366cc;background:none;\" title=\"Kepulauan Nusa Tenggara\" href=\"https://id.wikipedia.org/wiki/Kepulauan_Nusa_Tenggara\">Kepulauan Nusa Tenggara</a>. Di awal <a style=\"color:#3366cc;background:none;\" title=\"Kemerdekaan\" href=\"https://id.wikipedia.org/wiki/Kemerdekaan\">kemerdekaan</a> Indonesia, pulau ini termasuk dalam Provinsi <a class=\"mw-redirect\" style=\"color:#3366cc;background:none;\" title=\"Sunda Kecil\" href=\"https://id.wikipedia.org/wiki/Sunda_Kecil\">Sunda Kecil</a> yang beribu kota di <a style=\"color:#3366cc;background:none;\" title=\"Singaraja\" href=\"https://id.wikipedia.org/wiki/Singaraja\">Singaraja</a>, dan kini terbagi menjadi 3 provinsi, yakni Bali, <a style=\"color:#3366cc;background:none;\" title=\"Nusa Tenggara Barat\" href=\"https://id.wikipedia.org/wiki/Nusa_Tenggara_Barat\">Nusa Tenggara Barat</a>, dan <a style=\"color:#3366cc;background:none;\" title=\"Nusa Tenggara Timur\" href=\"https://id.wikipedia.org/wiki/Nusa_Tenggara_Timur\">Nusa Tenggara Timur</a> .<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://id.wikipedia.org/wiki/Bali#cite_note-9\">[9]</a></sup><sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://id.wikipedia.org/wiki/Bali#cite_note-10\">[10]</a></sup> Pada tahun <a style=\"color:#3366cc;background:none;\" title=\"2020\" href=\"https://id.wikipedia.org/wiki/2020\">2020</a>, penduduk provinsi Bali berjumlah 4.317.404 jiwa, dengan kepadatan 747 jiwa/km<sup style=\"line-height:1;font-size:11.2px;\">2</sup>.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://id.wikipedia.org/wiki/Bali#cite_note-BALI-5\">[5]</a></sup></p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Selain terdiri dari pulau Bali, wilayah provinsi Bali juga terdiri dari pulau-pulau yang lebih kecil di sekitarnya, yaitu pulau <a style=\"color:#3366cc;background:none;\" title=\"Nusa Penida\" href=\"https://id.wikipedia.org/wiki/Nusa_Penida\">Nusa Penida</a>, pulau <a style=\"color:#3366cc;background:none;\" title=\"Nusa Lembongan\" href=\"https://id.wikipedia.org/wiki/Nusa_Lembongan\">Nusa Lembongan</a>, pulau <a style=\"color:#3366cc;background:none;\" title=\"Nusa Ceningan\" href=\"https://id.wikipedia.org/wiki/Nusa_Ceningan\">Nusa Ceningan</a>, <a class=\"mw-redirect\" style=\"color:#3366cc;background:none;\" title=\"Pulau Serangan\" href=\"https://id.wikipedia.org/wiki/Pulau_Serangan\">Pulau Serangan</a>, dan Pulau Menjangan. Secara geografis, Bali terletak di antara Pulau <a style=\"color:#3366cc;background:none;\" title=\"Jawa\" href=\"https://id.wikipedia.org/wiki/Jawa\">Jawa</a> dan Pulau <a class=\"mw-redirect\" style=\"color:#3366cc;background:none;\" title=\"Lombok\" href=\"https://id.wikipedia.org/wiki/Lombok\">Lombok</a>. Mayoritas penduduk Bali adalah pemeluk agama <a class=\"mw-redirect\" style=\"color:#3366cc;background:none;\" title=\"Agama Hindu Dharma\" href=\"https://id.wikipedia.org/wiki/Agama_Hindu_Dharma\">Hindu</a>.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://id.wikipedia.org/wiki/Bali#cite_note-AGAMA-4\">[4]</a></sup> Di dunia, Bali terkenal sebagai tujuan <a style=\"color:#3366cc;background:none;\" title=\"Pariwisata\" href=\"https://id.wikipedia.org/wiki/Pariwisata\">pariwisata</a> dengan keunikan berbagai hasil seni-budayanya dan juga mitosnya, khususnya bagi para wisatawan <a style=\"color:#3366cc;background:none;\" title=\"Jepang\" href=\"https://id.wikipedia.org/wiki/Jepang\">Jepang</a> dan <a style=\"color:#3366cc;background:none;\" title=\"Australia\" href=\"https://id.wikipedia.org/wiki/Australia\">Australia</a>. Bali juga dikenal dengan julukan <em>Pulau Dewata</em> dan <em>Pulau Seribu Pura</em>.</p>', 11, 11, '2023-09-11 04:00:00', '2023-09-11 04:07:20', NULL),
(2, 11, 'en', 'Bali', '<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\"><strong>Bali</strong> (<span class=\"rt-commentedText nowrap\" style=\"white-space:nowrap;\"><span class=\"IPA nopopups noexcerpt\" lang=\"en-fonipa\" xml:lang=\"en-fonipa\"><a style=\"color:#3366cc;background:none;\" title=\"Help:IPA/English\" href=\"https://en.wikipedia.org/wiki/Help:IPA/English\">/<span style=\"border-bottom:1px dotted;\"><span title=\"/ˈ/: primary stress follows\">ˈ</span><span title=\"\'b\' in \'buy\'\">b</span><span title=\"/ɑː/: \'a\' in \'father\'\">ɑː</span><span title=\"\'l\' in \'lie\'\">l</span><span title=\"/i/: \'y\' in \'happy\'\">i</span></span>/</a></span></span>; <a style=\"color:#3366cc;background:none;\" title=\"Balinese language\" href=\"https://en.wikipedia.org/wiki/Balinese_language\">Balinese</a>: <span lang=\"ban\" xml:lang=\"ban\">ᬩᬮᬶ</span>) is a <a style=\"color:#3366cc;background:none;\" title=\"Provinces of Indonesia\" href=\"https://en.wikipedia.org/wiki/Provinces_of_Indonesia\">province</a> of <a style=\"color:#3366cc;background:none;\" title=\"Indonesia\" href=\"https://en.wikipedia.org/wiki/Indonesia\">Indonesia</a> and the westernmost of the <a style=\"color:#3366cc;background:none;\" title=\"Lesser Sunda Islands\" href=\"https://en.wikipedia.org/wiki/Lesser_Sunda_Islands\">Lesser Sunda Islands</a>. East of <a style=\"color:#3366cc;background:none;\" title=\"Java\" href=\"https://en.wikipedia.org/wiki/Java\">Java</a> and west of <a style=\"color:#3366cc;background:none;\" title=\"Lombok\" href=\"https://en.wikipedia.org/wiki/Lombok\">Lombok</a>, the province includes the island of Bali and a few smaller offshore islands, notably <a style=\"color:#3366cc;background:none;\" title=\"Nusa Penida\" href=\"https://en.wikipedia.org/wiki/Nusa_Penida\">Nusa Penida</a>, <a style=\"color:#3366cc;background:none;\" title=\"Nusa Lembongan\" href=\"https://en.wikipedia.org/wiki/Nusa_Lembongan\">Nusa Lembongan</a>, and <a style=\"color:#3366cc;background:none;\" title=\"Nusa Ceningan\" href=\"https://en.wikipedia.org/wiki/Nusa_Ceningan\">Nusa Ceningan</a> to the southeast. The provincial capital, <a style=\"color:#3366cc;background:none;\" title=\"Denpasar\" href=\"https://en.wikipedia.org/wiki/Denpasar\">Denpasar</a>,<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-7\">[7]</a></sup> is the <a style=\"color:#3366cc;background:none;\" title=\"List of Indonesian cities by population\" href=\"https://en.wikipedia.org/wiki/List_of_Indonesian_cities_by_population\">most populous city</a> in the Lesser Sunda Islands and the second-largest, after <a style=\"color:#3366cc;background:none;\" title=\"Makassar\" href=\"https://en.wikipedia.org/wiki/Makassar\">Makassar</a>, in <a class=\"mw-redirect\" style=\"color:#3366cc;background:none;\" title=\"Eastern Indonesia\" href=\"https://en.wikipedia.org/wiki/Eastern_Indonesia\">Eastern Indonesia</a>. The upland town of <a style=\"color:#3366cc;background:none;\" title=\"Ubud\" href=\"https://en.wikipedia.org/wiki/Ubud\">Ubud</a> in Greater Denpasar is considered Bali\'s cultural centre. The province is Indonesia\'s main tourist destination, with a significant rise in tourism since the 1980s.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-8\">[8]</a></sup> Tourism-related business makes up 80% of its economy.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-tourism-9\">[9]</a></sup></p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Bali is the only <a style=\"color:#3366cc;background:none;\" title=\"Hinduism in Indonesia\" href=\"https://en.wikipedia.org/wiki/Hinduism_in_Indonesia\">Hindu-majority province</a> in Indonesia, with 86.9% of the population adhering to <a style=\"color:#3366cc;background:none;\" title=\"Balinese Hinduism\" href=\"https://en.wikipedia.org/wiki/Balinese_Hinduism\">Balinese Hinduism</a>.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-census2010-3\">[3]</a></sup> It is renowned for its highly developed arts, including traditional and modern dance, sculpture, painting, leather, metalworking, and music. The Indonesian International Film Festival is held every year in Bali. Other international events that have been held in Bali include <a style=\"color:#3366cc;background:none;\" title=\"Miss World 2013\" href=\"https://en.wikipedia.org/wiki/Miss_World_2013\">Miss World 2013</a>, the 2018 <a style=\"color:#3366cc;background:none;\" title=\"Annual Meetings of the International Monetary Fund and the World Bank Group\" href=\"https://en.wikipedia.org/wiki/Annual_Meetings_of_the_International_Monetary_Fund_and_the_World_Bank_Group\">Annual Meetings of the International Monetary Fund and the World Bank Group</a> and the <a style=\"color:#3366cc;background:none;\" title=\"2022 G20 Bali summit\" href=\"https://en.wikipedia.org/wiki/2022_G20_Bali_summit\">2022 G20 summit</a>. In March 2017, <a class=\"mw-redirect\" style=\"color:#3366cc;background:none;\" title=\"TripAdvisor\" href=\"https://en.wikipedia.org/wiki/TripAdvisor\">TripAdvisor</a> named Bali as the world\'s top destination in its Traveller\'s Choice award, which it also earned in January 2021.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-10\">[10]</a></sup><sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-11\">[11]</a></sup></p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Bali is part of the <a style=\"color:#3366cc;background:none;\" title=\"Coral Triangle\" href=\"https://en.wikipedia.org/wiki/Coral_Triangle\">Coral Triangle</a>, the area with the highest biodiversity of marine species, especially fish and turtles.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-12\">[12]</a></sup> In this area alone, over 500 reef-building coral species can be found. For comparison, this is about seven times as many as in the entire <a style=\"color:#3366cc;background:none;\" title=\"Caribbean\" href=\"https://en.wikipedia.org/wiki/Caribbean\">Caribbean</a>.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-13\">[13]</a></sup> Bali is the home of the <a style=\"color:#3366cc;background:none;\" title=\"Subak (irrigation)\" href=\"https://en.wikipedia.org/wiki/Subak_(irrigation)\">Subak irrigation system</a>, a <a style=\"color:#3366cc;background:none;\" title=\"UNESCO\" href=\"https://en.wikipedia.org/wiki/UNESCO\">UNESCO</a> <a style=\"color:#3366cc;background:none;\" title=\"World Heritage Site\" href=\"https://en.wikipedia.org/wiki/World_Heritage_Site\">World Heritage Site</a>.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-14\">[14]</a></sup> It is also home to a unified confederation of kingdoms composed of 10 traditional royal Balinese houses, each house ruling a specific geographic area. The confederation is the successor of the <a style=\"color:#3366cc;background:none;\" title=\"Bali Kingdom\" href=\"https://en.wikipedia.org/wiki/Bali_Kingdom\">Bali Kingdom</a>. The royal houses are not recognised by the government of Indonesia; however, they originated before <a style=\"color:#3366cc;background:none;\" title=\"Dutch East Indies\" href=\"https://en.wikipedia.org/wiki/Dutch_East_Indies\">Dutch colonisation</a>.<sup class=\"reference\" style=\"line-height:1;white-space:nowrap;font-size:11.2px;\"><a style=\"color:#3366cc;background:none;\" href=\"https://en.wikipedia.org/wiki/Bali#cite_note-15\">[15]</a></sup></p>', 11, NULL, '2023-09-11 04:05:20', '2023-09-11 04:05:20', '[{\"image_id\":\"240\",\"title\":null,\"link\":null,\"content\":null}]'),
(3, 11, 'it', 'Bali', '<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">La presenza umana nell\'isola risale alla <a style=\"color:#0645ad;background:none;\" title=\"Preistoria\" href=\"https://it.wikipedia.org/wiki/Preistoria\">preistoria</a>. Alcuni reperti risalenti al <a style=\"color:#0645ad;background:none;\" title=\"XXXI secolo a.C.\" href=\"https://it.wikipedia.org/wiki/XXXI_secolo_a.C.\">3000 a.C.</a>, ritrovati nei dintorni del villaggio di <a class=\"new\" style=\"color:#ba0000;background:none;\" title=\"Cekik (la pagina non esiste)\" href=\"https://it.wikipedia.org/w/index.php?title=Cekik&amp;action=edit&amp;redlink=1\">Cekik</a> nella parte ovest dell\'isola, testimoniano l\'insediamento di popolazioni migrate in tempi preistorici dal continente asiatico. Le prime tracce storiche identificate nell\'isola sono cocci con iscrizioni <a style=\"color:#0645ad;background:none;\" title=\"Bramino\" href=\"https://it.wikipedia.org/wiki/Bramino\">braminiche</a>, databili intorno al <a style=\"color:#0645ad;background:none;\" title=\"I secolo a.C.\" href=\"https://it.wikipedia.org/wiki/I_secolo_a.C.\">I secolo a.C.</a>, che testimoniano l\'arrivo di popolazioni indù nell\'isola.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Tra i più antichi documenti scritti ritrovati a Bali vi è la \"carta di Blanjoung\", redatta in <a style=\"color:#0645ad;background:none;\" title=\"Lingua sanscrita\" href=\"https://it.wikipedia.org/wiki/Lingua_sanscrita\">sanscrito</a> e risalente al <a style=\"color:#0645ad;background:none;\" title=\"913\" href=\"https://it.wikipedia.org/wiki/913\">913</a> d.C., che menziona il sovrano Sri Kesari Warmadewa e il luogo «Walidwipa». Un\'iscrizione del <a style=\"color:#0645ad;background:none;\" title=\"1041\" href=\"https://it.wikipedia.org/wiki/1041\">1041</a> incisa su una pietra ritrovata a Giava (detta \"Pietra di Calcutta\" in quanto conservata al <a class=\"new\" style=\"color:#ba0000;background:none;\" title=\"Museo Indiano (la pagina non esiste)\" href=\"https://it.wikipedia.org/w/index.php?title=Museo_Indiano&amp;action=edit&amp;redlink=1\">Museo Indiano</a> di <a style=\"color:#0645ad;background:none;\" title=\"Calcutta\" href=\"https://it.wikipedia.org/wiki/Calcutta\">Calcutta</a>) riporta la genealogia del re Airlangga, figlio del principe balinese Udayana. In questo lungo periodo di tempo venne sviluppato il sistema di irrigazione <em><a style=\"color:#0645ad;background:none;\" title=\"Subak\" href=\"https://it.wikipedia.org/wiki/Subak\">subak</a></em> per la <a style=\"color:#0645ad;background:none;\" title=\"Risicoltura\" href=\"https://it.wikipedia.org/wiki/Risicoltura\">coltivazione del riso</a>. Risalgono a questo periodo, inoltre, alcune tradizioni religiose e culturali che esistono tuttora.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Nel <a style=\"color:#0645ad;background:none;\" title=\"1343\" href=\"https://it.wikipedia.org/wiki/1343\">1343</a> l\'Impero <a style=\"color:#0645ad;background:none;\" title=\"Majapahit\" href=\"https://it.wikipedia.org/wiki/Majapahit\">Majapahit</a>, che era insediato nella parte orientale di <a style=\"color:#0645ad;background:none;\" title=\"Giava\" href=\"https://it.wikipedia.org/wiki/Giava\">Giava</a>, fondò una colonia a Bali. L\'isola venne nuovamente menzionata su testi giavanesi tra il <a style=\"color:#0645ad;background:none;\" title=\"1059\" href=\"https://it.wikipedia.org/wiki/1059\">1059</a> e il <a style=\"color:#0645ad;background:none;\" title=\"1205\" href=\"https://it.wikipedia.org/wiki/1205\">1205</a> nel <em>Nagarakertagama</em>, poema epico scritto nel <a style=\"color:#0645ad;background:none;\" title=\"1365\" href=\"https://it.wikipedia.org/wiki/1365\">1365</a> sotto il regno di Hayam Wuruk dell\'Impero <a style=\"color:#0645ad;background:none;\" title=\"Majapahit\" href=\"https://it.wikipedia.org/wiki/Majapahit\">Majapahit</a> (1350-1389). All\'inizio del <a style=\"color:#0645ad;background:none;\" title=\"XVI secolo\" href=\"https://it.wikipedia.org/wiki/XVI_secolo\">XVI secolo</a>, con il declino dell\'impero e la successiva occupazione di Giava da parte delle truppe del re musulmano di Demak, vi fu un esodo di artisti, religiosi ed intellettuali verso la colonia balinese del re <a class=\"external text\" style=\"color:#3366bb;background:url(&quot;/w/skins/Vector/resources/common/images/link-external-small-ltr-progressive.svg?30a3a&quot;) no-repeat right center;padding-right:1em;\" href=\"https://maxwin.datuk168rtp.com/\">datuk168</a>.</p>', 11, 11, '2023-09-11 04:07:31', '2023-09-11 04:07:55', NULL),
(4, 12, 'id', NULL, NULL, 11, NULL, '2023-09-27 23:59:34', '2023-09-27 23:59:34', NULL),
(5, 1, 'id', 'Paris', '<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\"><strong>Parigi</strong> è la <a style=\"color:#0645ad;background:none;\" title=\"Capitale (città)\" href=\"https://it.wikipedia.org/wiki/Capitale_(citt%C3%A0)\">capitale</a> e la <a style=\"color:#0645ad;background:none;\" title=\"Città\" href=\"https://it.wikipedia.org/wiki/Citt%C3%A0\">città</a> più popolata della <a style=\"color:#0645ad;background:none;\" title=\"Francia\" href=\"https://it.wikipedia.org/wiki/Francia\">Francia</a>, capoluogo della <a style=\"color:#0645ad;background:none;\" title=\"Regioni della Francia\" href=\"https://it.wikipedia.org/wiki/Regioni_della_Francia\">regione</a> dell\'<a style=\"color:#0645ad;background:none;\" title=\"Île-de-France\" href=\"https://it.wikipedia.org/wiki/%C3%8Ele-de-France\">Île-de-France</a> e l\'unico <a style=\"color:#0645ad;background:none;\" title=\"Comuni della Francia\" href=\"https://it.wikipedia.org/wiki/Comuni_della_Francia\">comune</a> a essere nello stesso tempo <a style=\"color:#0645ad;background:none;\" title=\"Dipartimenti della Francia\" href=\"https://it.wikipedia.org/wiki/Dipartimenti_della_Francia\">dipartimento</a>, secondo la riforma del 1977 e i dettami della <a style=\"color:#0645ad;background:none;\" title=\"Legge PML\" href=\"https://it.wikipedia.org/wiki/Legge_PML\">legge PML</a> che espansero i vecchi confini comunali.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Con una popolazione di 2 229 095 abitanti è, dopo <a style=\"color:#0645ad;background:none;\" title=\"Berlino\" href=\"https://it.wikipedia.org/wiki/Berlino\">Berlino</a>, <a style=\"color:#0645ad;background:none;\" title=\"Madrid\" href=\"https://it.wikipedia.org/wiki/Madrid\">Madrid</a>, <a style=\"color:#0645ad;background:none;\" title=\"Roma\" href=\"https://it.wikipedia.org/wiki/Roma\">Roma</a> e <a style=\"color:#0645ad;background:none;\" title=\"Bucarest\" href=\"https://it.wikipedia.org/wiki/Bucarest\">Bucarest</a>, il <a style=\"color:#0645ad;background:none;\" title=\"Comuni dell\'Unione europea per popolazione\" href=\"https://it.wikipedia.org/wiki/Comuni_dell%27Unione_europea_per_popolazione\">quinto comune</a> più popoloso dell\'<a style=\"color:#0645ad;background:none;\" title=\"Unione europea\" href=\"https://it.wikipedia.org/wiki/Unione_europea\">Unione europea</a> e, in considerazione della superficie comunale, possiede una delle più alte densità abitative del mondo. Tuttavia, l\'estensione urbana della capitale francese è ben più ampia del suo territorio comunale: la sua <a style=\"color:#0645ad;background:none;\" title=\"Area metropolitana di Parigi\" href=\"https://it.wikipedia.org/wiki/Area_metropolitana_di_Parigi\">area metropolitana</a>, detta anche \"Grande Parigi\" (in francese <em>Grand Paris</em>), conta infatti circa 12 milioni di persone.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">La città si trova nel nord della <a style=\"color:#0645ad;background:none;\" title=\"Francia\" href=\"https://it.wikipedia.org/wiki/Francia\">Francia</a>, su un\'<a style=\"color:#0645ad;background:none;\" title=\"Meandro\" href=\"https://it.wikipedia.org/wiki/Meandro\">ansa</a> della <a style=\"color:#0645ad;background:none;\" title=\"Senna\" href=\"https://it.wikipedia.org/wiki/Senna\">Senna</a>, posizione molto favorevole poiché fondamentale snodo di trasporti e traffici del <a style=\"color:#0645ad;background:none;\" title=\"Europa\" href=\"https://it.wikipedia.org/wiki/Europa\">continente europeo</a>. In effetti, la posizione di Parigi al centro dei principali itinerari commerciali terrestri e fluviali le permise di diventare una delle città più influenti della Francia a partire dal <a style=\"color:#0645ad;background:none;\" title=\"X secolo\" href=\"https://it.wikipedia.org/wiki/X_secolo\">X secolo</a>, con la costruzione dei palazzi reali, di ricche abbazie e della celebre <a style=\"color:#0645ad;background:none;\" title=\"Cattedrale di Notre-Dame\" href=\"https://it.wikipedia.org/wiki/Cattedrale_di_Notre-Dame\">cattedrale di Notre-Dame</a>.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Lungo tutto il corso della propria storia, Parigi ha saputo influenzare in modo determinante la <a style=\"color:#0645ad;background:none;\" title=\"Politica\" href=\"https://it.wikipedia.org/wiki/Politica\">politica</a>, la <a style=\"color:#0645ad;background:none;\" title=\"Cultura\" href=\"https://it.wikipedia.org/wiki/Cultura\">cultura</a>, lo stile di vita e l\'<a style=\"color:#0645ad;background:none;\" title=\"Economia\" href=\"https://it.wikipedia.org/wiki/Economia\">economia</a> dell\'intero mondo occidentale. Nel <a style=\"color:#0645ad;background:none;\" title=\"XIII secolo\" href=\"https://it.wikipedia.org/wiki/XIII_secolo\">XIII secolo</a> diede grande impulso alla rinascita delle arti e del sapere grazie alla presenza della prestigiosa Università della <a style=\"color:#0645ad;background:none;\" title=\"Sorbona\" href=\"https://it.wikipedia.org/wiki/Sorbona\">Sorbona</a> nel <a style=\"color:#0645ad;background:none;\" title=\"Quartiere latino (Parigi)\" href=\"https://it.wikipedia.org/wiki/Quartiere_latino_(Parigi)\">Quartiere latino</a>; nel <a style=\"color:#0645ad;background:none;\" title=\"XIV secolo\" href=\"https://it.wikipedia.org/wiki/XIV_secolo\">XIV secolo</a> divenne una delle più importanti città del mondo cristiano. Nell\'Età moderna la sua influenza continuò a crescere in tutti i sensi: nella seconda metà del <a style=\"color:#0645ad;background:none;\" title=\"XVII secolo\" href=\"https://it.wikipedia.org/wiki/XVII_secolo\">XVII secolo</a> fu la capitale della più grande potenza militare del continente, nel Settecento divenne il cenacolo europeo della cultura e dei \"lumi\", per poi avviarsi nell\'Ottocento a divenire la città dell\'<a style=\"color:#0645ad;background:none;\" title=\"Arte\" href=\"https://it.wikipedia.org/wiki/Arte\">arte</a>, dei piaceri e del divertimento.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Ereditando la storia di un <a style=\"color:#0645ad;background:none;\" title=\"Impero coloniale francese\" href=\"https://it.wikipedia.org/wiki/Impero_coloniale_francese\">impero coloniale</a> estesosi su cinque continenti, Parigi è considerata come il centro del mondo francofono e ha mantenuto una posizione internazionale di grande rilievo, sia come influente metropoli mondiale, sia come centro culturale, politico ed economico di indiscusso prestigio. Ospita, tra gli altri, il quartier generale dell\'<a style=\"color:#0645ad;background:none;\" title=\"Organizzazione per la cooperazione e lo sviluppo economico\" href=\"https://it.wikipedia.org/wiki/Organizzazione_per_la_cooperazione_e_lo_sviluppo_economico\">OECD</a>, dell\'<a style=\"color:#0645ad;background:none;\" title=\"UNESCO\" href=\"https://it.wikipedia.org/wiki/UNESCO\">UNESCO</a> e dell\'<a style=\"color:#0645ad;background:none;\" title=\"Agenzia spaziale europea\" href=\"https://it.wikipedia.org/wiki/Agenzia_spaziale_europea\">ESA</a>. Secondo stime effettuate dalla CNN, nel 2009<sup class=\"reference\" style=\"line-height:1;font-size:0.7rem;white-space:nowrap;\"><a style=\"color:#0645ad;background:none;\" href=\"https://it.wikipedia.org/wiki/Parigi#cite_note-http://money.cnn.com/magazines/fortune/global500/2009/cities/-2\">[2]</a></sup> Parigi era sede di 27 delle aziende <em><a style=\"color:#0645ad;background:none;\" title=\"Fortune Global 500\" href=\"https://it.wikipedia.org/wiki/Fortune_Global_500\">Fortune Global 500</a></em>, davanti a <a style=\"color:#0645ad;background:none;\" title=\"Pechino\" href=\"https://it.wikipedia.org/wiki/Pechino\">Pechino</a>, <a style=\"color:#0645ad;background:none;\" title=\"New York\" href=\"https://it.wikipedia.org/wiki/New_York\">New York</a> e <a style=\"color:#0645ad;background:none;\" title=\"Londra\" href=\"https://it.wikipedia.org/wiki/Londra\">Londra</a>. La presenza in città di una delle più importanti borse internazionali e le sue numerose attività economiche, politiche e turistiche, fanno di Parigi uno dei principali centri del mondo. La città è anche un punto di riferimento per gli <a class=\"mw-redirect\" style=\"color:#0645ad;background:none;\" title=\"Stilisti\" href=\"https://it.wikipedia.org/wiki/Stilisti\">stilisti</a> e per la <a style=\"color:#0645ad;background:none;\" title=\"Moda\" href=\"https://it.wikipedia.org/wiki/Moda\">moda</a>, essendone considerata una delle <a style=\"color:#0645ad;background:none;\" title=\"Capitale della moda\" href=\"https://it.wikipedia.org/wiki/Capitale_della_moda\">capitali mondiali</a> insieme a <a style=\"color:#0645ad;background:none;\" title=\"Milano\" href=\"https://it.wikipedia.org/wiki/Milano\">Milano</a>, <a style=\"color:#0645ad;background:none;\" title=\"Londra\" href=\"https://it.wikipedia.org/wiki/Londra\">Londra</a> e <a style=\"color:#0645ad;background:none;\" title=\"New York\" href=\"https://it.wikipedia.org/wiki/New_York\">New York</a>.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Scrigno contenente numerosi monumenti dall\'incalcolabile valore storico e artistico, Parigi rappresenta il simbolo stesso della cultura francese e del suo prestigio nel mondo. I turisti spesso le attribuiscono il qualificativo di \"più romantica città del globo\", titolo derivato dal periodo del <a style=\"color:#0645ad;background:none;\" title=\"Secondo Impero francese\" href=\"https://it.wikipedia.org/wiki/Secondo_Impero_francese\">Secondo Impero</a> durante il quale Parigi <a style=\"color:#0645ad;background:none;\" title=\"Trasformazione di Parigi sotto il Secondo Impero\" href=\"https://it.wikipedia.org/wiki/Trasformazione_di_Parigi_sotto_il_Secondo_Impero\">fu profondamente trasformata</a> dal <a style=\"color:#0645ad;background:none;\" title=\"Barone Haussmann\" href=\"https://it.wikipedia.org/wiki/Barone_Haussmann\">barone Haussmann</a>, guidato dall\'imperatore <a style=\"color:#0645ad;background:none;\" title=\"Napoleone III di Francia\" href=\"https://it.wikipedia.org/wiki/Napoleone_III_di_Francia\">Napoleone III</a> che voleva fare della capitale francese la più bella città d\'<a style=\"color:#0645ad;background:none;\" title=\"Europa\" href=\"https://it.wikipedia.org/wiki/Europa\">Europa</a>. Quella di Parigi fu infatti una delle più grandi e più criticate rivoluzioni urbanistiche (visto lo sventramento del cuore storico della città) nella storia dell\'umanità. Nel 1989 fu nominata,assieme a Roma <a class=\"mw-redirect\" style=\"color:#0645ad;background:none;\" title=\"Città europea della cultura\" href=\"https://it.wikipedia.org/wiki/Citt%C3%A0_europea_della_cultura\">città europea della cultura</a>.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">La città è stata sede di ben cinque <a style=\"color:#0645ad;background:none;\" title=\"Esposizione universale\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale\">esposizioni universali</a> (<a style=\"color:#0645ad;background:none;\" title=\"Esposizione universale dei prodotti dell\'agricoltura, dell\'industria e delle belle arti di Parigi (1855)\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale_dei_prodotti_dell%27agricoltura,_dell%27industria_e_delle_belle_arti_di_Parigi_(1855)\">1855</a>, <a style=\"color:#0645ad;background:none;\" title=\"Esposizione universale di Parigi (1867)\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale_di_Parigi_(1867)\">1867</a>, <a style=\"color:#0645ad;background:none;\" title=\"Esposizioni universali di Parigi\" href=\"https://it.wikipedia.org/wiki/Esposizioni_universali_di_Parigi\">1878</a>, <a style=\"color:#0645ad;background:none;\" title=\"Esposizione universale di Parigi (1889)\" href=\"https://it.wikipedia.org/wiki/Esposizione_universale_di_Parigi_(1889)\">1889</a> e <a style=\"color:#0645ad;background:none;\" title=\"Esposizione di Parigi (1900)\" href=\"https://it.wikipedia.org/wiki/Esposizione_di_Parigi_(1900)\">1900</a>), più di qualunque altra città, che ne hanno in parte modellato l\'aspetto nel <a style=\"color:#0645ad;background:none;\" title=\"XX secolo\" href=\"https://it.wikipedia.org/wiki/XX_secolo\">XX secolo</a> e ha ospitato due edizioni dei <a class=\"mw-redirect\" style=\"color:#0645ad;background:none;\" title=\"Giochi Olimpici\" href=\"https://it.wikipedia.org/wiki/Giochi_Olimpici\">Giochi Olimpici</a> (<a style=\"color:#0645ad;background:none;\" title=\"Giochi della II Olimpiade\" href=\"https://it.wikipedia.org/wiki/Giochi_della_II_Olimpiade\">1900</a> e <a style=\"color:#0645ad;background:none;\" title=\"Giochi della VIII Olimpiade\" href=\"https://it.wikipedia.org/wiki/Giochi_della_VIII_Olimpiade\">1924</a>) e ospiterà l\'edizione dei giochi del <a style=\"color:#0645ad;background:none;\" title=\"Giochi della XXXIII Olimpiade\" href=\"https://it.wikipedia.org/wiki/Giochi_della_XXXIII_Olimpiade\">2024</a>.</p>\n<p style=\"margin:0.5em 0px;color:#202122;font-family:sans-serif;font-size:14px;background-color:#ffffff;\">Uno studio dell\'Institut d\'aménagement et d\'urbanisme (IAU) pubblicato nel 2019 sottolinea che i prezzi degli alloggi spingono i nuclei familiari a basso reddito a lasciare Parigi per stabilirsi nei dipartimenti vicini come <a style=\"color:#0645ad;background:none;\" title=\"Senna-Saint-Denis\" href=\"https://it.wikipedia.org/wiki/Senna-Saint-Denis\">Senna-Saint-Denis</a>, il che tende a provocare una \"<a style=\"color:#0645ad;background:none;\" title=\"Gentrificazione\" href=\"https://it.wikipedia.org/wiki/Gentrificazione\">gentrificazione</a>\" della capitale e una pauperizzazione dei dipartimenti vicini.<sup class=\"reference\" style=\"line-height:1;font-size:0.7rem;white-space:nowrap;\"><a style=\"color:#0645ad;background:none;\" href=\"https://it.wikipedia.org/wiki/Parigi#cite_note-3\">[3]</a></sup> Secondo il sito money.it, nel 2020, Parigi è la città più cara al mondo assieme a <a style=\"color:#0645ad;background:none;\" title=\"Hong Kong\" href=\"https://it.wikipedia.org/wiki/Hong_Kong\">Hong Kong</a> e <a style=\"color:#0645ad;background:none;\" title=\"Zurigo\" href=\"https://it.wikipedia.org/wiki/Zurigo\">Zurigo</a>.<sup class=\"reference\" style=\"line-height:1;font-size:0.7rem;white-space:nowrap;\"><a style=\"color:#0645ad;background:none;\" href=\"https://it.wikipedia.org/wiki/Parigi#cite_note-4\">[4]</a></sup></p>', 11, 11, '2023-10-11 00:03:23', '2023-11-05 00:12:43', '[{\"image_id\":\"113\",\"title\":\"Experiencing the best jazz in Harlem, birthplace of bebop\",\"link\":\"#\",\"content\":\"New Orleans might be the home of jazz, but New York City is where many of the genre\\u2019s greats became stars \\u2013 and Harlem was at the heart of it.The neighborhood experienced a rebirth during the...\"},{\"image_id\":\"114\",\"title\":\"Reflections from the road: transformative \\u2018Big Trip\\u2019 experiences\",\"link\":\"#\",\"content\":\"Whether it\\u2019s a gap year after finishing school, a well-earned sabbatical from work or an overseas adventure in celebration of your retirement, a big trip is a rite of passage for every traveller, with myriad life lessons to be ...\"},{\"image_id\":\"249\",\"title\":\"LOUVRE\",\"link\":\"https:\\/\\/www.louvre.fr\\/en\",\"content\":\"There are plenty of good reasons to visit the Louvre! So many works of art to discover in this fabulous museum that used to be a palace!\"}]');
