(15, 'adventages', 'Adventages', '<h4 style=\"font-family:Roboto, sans-serif;font-weight:400;line-height:30px;color:#242429;margin-bottom:10px;margin-top:10px;font-size:18px;background-color:#ffffff;\"><span style=\"font-weight:600;\">Virtuard adalah platform berdasarkan pengumuman dan tur virtual yang dapat dilampirkan pada pengumuman Anda untuk siapa saja dan tipe apa saja yang ingin menggunakan layanan ini. </span></h4>\n<h4 style=\"font-family:Roboto, sans-serif;font-weight:400;line-height:30px;color:#242429;margin-bottom:10px;margin-top:10px;font-size:18px;background-color:#ffffff;\"><span style=\"font-weight:600;\">Namun, sebelum melanjutkan, lebih baik menghabiskan beberapa kata untuk menjelaskan apa itu Tur Virtual.</span></h4>', NULL, 'publish', NULL, NULL, 14, 1, 9, 9, '2023-08-15 23:07:22', NULL, NULL, '2023-08-15 21:54:10', '2023-08-15 23:07:22', 'transparent', NULL, NULL),
(16, 'adventages', 'Adventages', '<h4 style=\"font-family:Roboto, sans-serif;font-weight:400;line-height:30px;color:#242429;margin-bottom:10px;margin-top:10px;font-size:18px;background-color:#ffffff;\">asasdasd</h4>', NULL, 'publish', NULL, NULL, 15, 1, 9, 9, '2023-08-15 23:23:41', NULL, NULL, '2023-08-15 23:07:38', '2023-08-15 23:23:41', 'transparent', NULL, NULL),
(17, 'adventages', 'Adventages', '<h4 style=\"font-family:Roboto, sans-serif;font-weight:400;line-height:30px;color:#242429;margin-bottom:10px;margin-top:10px;font-size:18px;background-color:#ffffff;\"><span style=\"font-weight:600;\">Virtuard is a platform based on announcements and virtual tours that can be attached to your announcement for anyone and any type who wants to use this service. </span></h4>\n<h4 style=\"font-family:Roboto, sans-serif;font-weight:400;line-height:30px;color:#242429;margin-bottom:10px;margin-top:10px;font-size:18px;background-color:#ffffff;\"><span style=\"font-weight:600;\">Before proceeding, however, it is better to spend a few words to explain what the Virtual Tour is.</span></h4>\n<p> </p>\n<h5 style=\"font-family:Roboto, sans-serif;font-weight:400;line-height:30px;color:#242429;margin-bottom:10px;margin-top:10px;font-size:18px;background-color:#ffffff;\"><span style=\"vertical-align:inherit;\"><span style=\"background-color:transparent;vertical-align:inherit;\">The virtual tour is an interactive experience that allows you to virtually explore an environment or location without having to be physically present on site. </span><span style=\"background-color:transparent;vertical-align:inherit;\">It can be used in many situations, for example:</span></span></h5>', NULL, 'publish', NULL, NULL, 16, 1, 9, 9, NULL, NULL, NULL, '2023-08-15 23:24:30', '2023-08-15 23:25:37', 'transparent', NULL, NULL),
