(10, 'topbar_left_text', NULL, '<!--<div class=\"socials\">-->\r\n<!--<a href=\"https://www.facebook.com/virtuard\"><i class=\"fa fa-facebook\"></i></a>-->\r\n<!--<a href=\"https://www.instagram.com/virtuardtour\"><i class=\"fa fa-instagram\"></i></a>-->\r\n<!--<a href=\"https://twitter.com/virtuard\"><i class=\"fa fa-twitter\"></i></a>-->\r\n<!--</div>-->\r\n<!--<span class=\"line\"></span>-->\r\n<!--<a href=\"mailto:info@virtuard.com\">info@virtuard.com</a>-->\r\n<div class=\"d-flex align-items-center w-full\">\r\n    <a href=\"/\">\r\n        <img class=\"logo-header-new\" src=\"https://virtuard.com/wp-content/uploads/2022/09/cropped-Logo-Contorno-Bianco-copia-e1673010650937.png\">\r\n    </a>\r\n    <div class=\"w-full d-flex justify-content-between ml-4\">\r\n        <a class=\"menu-additional-header mr-4\" href=\'/explore\'>\r\n            Jelajahi\r\n        </a>\r\n        <a class=\"menu-additional-header mr-4\" href=\'/user/follow-boards\'>\r\n            Papan Pengumuman\r\n        </a>\r\n        <a class=\"menu-additional-header mr-4\" href=\'/user/follow-member\'>\r\n            Anggota\r\n        </a>\r\n        <!--<a class=\"menu-additional-header mr-4\" href=\'/page/maintenance\'>-->\r\n        <!--    Utilitas-->\r\n        <!--</a>-->\r\n        \r\n        <div class=\"dropdown header-widget widget-user widget-language flex-shrink-0\">\r\n            <div data-toggle=\"dropdown\" class=\"user-dropdown d-flex align-items-center\" aria-haspopup=\"true\" aria-expanded=\"false\">\r\n                <div class=\"user-info flex-grow-1 d-flex\">\r\n                    Utilitas\r\n                </div>\r\n                <i class=\"fa fa-angle-down\"></i>\r\n            </div>\r\n            <div class=\"dropdown-menu\" aria-labelledby=\"dropdownMenuButton\" style=\"\">\r\n                <a class=\"dropdown-item\" href=\"/page/events\">\r\n                    Acara\r\n                </a>\r\n                <a class=\"dropdown-item\" href=\"/page/adventages\">\r\n                    Keuntungan\r\n                </a>\r\n                <a class=\"dropdown-item\" href=\"/page/maintenance\">\r\n                    Tutorial\r\n                </a>\r\n                <a class=\"dropdown-item\" href=\"/page/prices\">\r\n                    Harga Layanan\r\n                </a>\r\n                <a class=\"dropdown-item\" href=\"/page/work-with-us\">\r\n                    Bekerja Dengan Kami\r\n                </a>\r\n                <a class=\"dropdown-item\" href=\"/page/shop\">\r\n                    PRO\r\n                </a>\r\n                <a class=\"dropdown-item\" href=\"https://www.virtuard.cloud/\">\r\n                    Sosial Kami\r\n                </a>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>', NULL, 1, 11, NULL, '2023-07-18 01:03:16', '2023-11-08 02:26:23'),
