(39, 'user_content_email_registered', NULL, '<h1 style=\"text-align: center\">Welcome!</h1>\r\n                    <h3>Hello [first_name] [last_name]</h3>\r\n                    <p>Thank you for signing up with Booking Core! We hope you enjoy your time with us.</p>\r\n                    <p>Regards,</p>\r\n                    <p>Booking Core</p>', NULL, NULL, NULL, NULL, '2023-07-18 01:03:17', '2023-07-18 01:03:17'),
