INSERT INTO `core_settings` (`id`, `name`, `group`, `val`, `autoload`, `create_user`, `update_user`, `lang`, `created_at`, `updated_at`) VALUES
(222, 'style_custom_css', NULL, '/*Top Bar*/\r\n.bravo_wrap .bravo_topbar {\r\n    background: #fff;\r\n}\r\n\r\n/*Header Logo*/\r\n.bravo-logo img {\r\n    width: 75px;\r\n}\r\n.bravo_wrap .bravo-form-search-all .container {\r\n    max-width: 1234px !important;\r\n}\r\n/*Call Action*/\r\n.bravo-call-to-action .container {\r\n    width: 100%;\r\n    max-width: 100%;\r\n    padding: 0;\r\n}\r\n.bravo-call-to-action .container .context .row {\r\n    max-width: 1140px;\r\n    margin: auto;\r\n}\r\n.bravo-call-to-action .container .context .row .title {\r\n    text-align: center;\r\n    font-size: 30px;\r\n    color: #FFF;\r\n}\r\n\r\n/*Search Tabs*/\r\n.bravo_wrap .bravo_form .form-content {\r\n    padding: 0 !important;\r\n}\r\n.nav.nav-tabs {\r\n    display: flex;\r\n    justify-content: center;\r\n    margin-bottom: 22px;\r\n}\r\n.g-field-search label {\r\n    font-size: 15px !important;\r\n    color: #000 !important;\r\n    font-weight: 500 !important;\r\n    line-height: 1.6 !important;\r\n}\r\n.btn-search {\r\n    border-radius: 100px !important;\r\n}\r\n.g-field-search i {\r\n    display: none;\r\n}\r\n.form-content .form-control, .form-content div, .form-content .render {\r\n    font-size: 14px !important;\r\n}\r\n.nav.nav-tabs li a {\r\n    background: transparent !important;\r\n    /*-webkit-transform: translateZ(0) !important;*/\r\n    /*border-radius: 0 !important;*/\r\n    /*color: #fff !important;*/\r\n    /*background: hsla(0,0%,100%,.15) !important;*/\r\n    /*border-bottom-left-radius: 0 !important;*/\r\n    /*border-bottom-right-radius: 0 !important;*/\r\n    /*-webkit-transition: background .15s ease-in-out !important;*/\r\n    /*transition: background .15s ease-in-out !important;*/\r\n    border-bottom: 1px solid transparent !important;\r\n    font-weight: 600 !important;\r\n}\r\n.nav.nav-tabs li a.active {\r\n    /*color: #0a0202 !important;*/\r\n    /*background-color: #fff !important;*/\r\n    /*border: 1px solid rgba(0,0,0,.15) !important;*/\r\n    /*border-bottom: 1px solid #fff !important;*/\r\n    background: transparent !important;\r\n        border-bottom: 1px solid #FFF !important;\r\n}\r\n.nav.nav-tabs li a i {\r\n    display: none;\r\n}\r\n.tab-content::before {\r\n    display: none;\r\n}\r\n.bravo-form-search-all   {\r\n    height: 100vh;\r\n    padding: 0 !important;\r\n    display: flex;\r\n    /* justify-content: center; */\r\n    align-items: center;\r\n}\r\n.form.bravo_form {\r\n    padding: 10px;\r\n    border-radius: 132px;\r\n    position: absolute;\r\n    width: 100%;\r\n}\r\n/*Footer*/\r\n.bravo_footer .mailchimp {\r\n    display: none;\r\n}\r\n/*Header*/\r\n.bravo_wrap .bravo_topbar {\r\n    z-index: 2;\r\n    position: fixed;\r\n    width: 100%;\r\n    -webkit-backdrop-filter: blur(3px);\r\n    background-color: white;\r\n    backdrop-filter: blur(5px);\r\n}\r\n.bravo_topbar .container {\r\n    max-width: 95%;\r\n}\r\n.topbar-items li a, .topbar-left a {\r\n    color: black;\r\n}\r\n.frontend-page.header-transparent .bravo_wrap .bravo_topbar {\r\n        background-color: rgb(0 0 0 / 60%) !important;\r\n}\r\n.logo-header-new {\r\n    background: #FFF;\r\n    padding: 10px;\r\n    border-radius: 24px;\r\n    width: 80px;\r\n}\r\n.bravo_header {\r\n    display: none;\r\n}\r\n/*.login::before {*/\r\n/*  content: \"\";*/\r\n/*  display: inline-block;*/\r\n/*  width: 14px;*/\r\n/*  height: 14px;*/\r\n/*  background-image: url(\"https://static.vecteezy.com/system/resources/previews/005/544/718/original/profile-icon-design-free-vector.jpg\");*/\r\n/*  background-size: cover;*/\r\n/*  background-position: center; */\r\n/*  margin-right: 5px; */\r\n/*}*/\r\n.bravo_wrap .bravo_topbar .content .topbar-left {\r\n    width: 70%;\r\n}\r\n.menu-additional-header {\r\n    color: #151515 !important;\r\n}\r\n.text-heading {\r\n    text-align: center;\r\n}\r\n/*Location Section*/\r\n.bravo-list-locations .title {\r\n    text-align: center;\r\n    color: #000;\r\n    margin-top: 4rem;\r\n}\r\n.bravo-list-hotel .title, .bravo-list-tour .title {\r\n    color: #000;\r\n    margin-top: 4rem;\r\n}\r\n.bravo-list-hotel .sub-title, .bravo-list-tour .sub-title {\r\n    margin-bottom: 4rem !important;\r\n}\r\n.bravo-list-locations .sub-title {\r\n    text-align: center;\r\n    margin-bottom: 4rem !important;\r\n}\r\n.bravo_wrap .bravo-list-hotel .item-loop {\r\n    border-radius: 8px;\r\n}\r\n.bravo_wrap .page-template-content .bravo-list-tour .item-tour {\r\n    border-radius: 8px !important;\r\n}\r\n.owl-carousel.owl-loaded {\r\n    position: relative !important;\r\n}\r\n.bravo_wrap .bravo-list-hotel .owl-nav .owl-next, .bravo_wrap .bravo-list-tour .owl-nav .owl-next {\r\n    border-radius: 8px;\r\n    color: #5e6d77;\r\n    border: 1px solid #5e6d77;\r\n    font-size: 32px;\r\n    outline: none;\r\n}\r\n.bravo_wrap .bravo-list-hotel .owl-nav .owl-prev, .bravo_wrap .bravo-list-tour .owl-nav .owl-prev {\r\n    border-radius: 8px;\r\n    color: #5e6d77;\r\n    border: 1px solid #5e6d77;\r\n    font-size: 32px;\r\n    outline: none;\r\n}\r\n.bravo-testimonial h3 {\r\n    font-size: 28px !important;\r\n    font-weight: 500 !important;\r\n    /* margin-bottom: 5px; */\r\n    color: #000 !important;\r\n    text-align: center !important;\r\n    margin: 4rem 0 !important;\r\n}\r\n.bravo_wrap .bravo_topbar .content .topbar-right .dropdown-menu {\r\n    background: rgb(255, 255, 255) !important;\r\n    padding: 15px !important;\r\n    box-shadow: rgba(0, 0, 0, 0.42) 9px 14px 32px -23px !important;\r\n    border-radius: 8px !important;\r\n    border: 0 !important;\r\n    min-width: 238px !important;\r\n}\r\n.bravo_wrap .bravo_topbar .content .topbar-right .dropdown-menu li a {\r\n    color: #768092 !important;\r\n}\r\n.bravo_wrap .bravo_topbar .content .topbar-right .dropdown-menu li a i {\r\n    display: none;\r\n}\r\n.smart-search .list-item {\r\n    color: #000;\r\n}\r\n\r\n/*Search Hotel*/\r\n.bravo_search_hotel .container .bravo-list-item,\r\n.bravo_search_space .container .bravo-list-item,\r\n.bravo_search_tour .container .bravo-list-item,\r\n.bravo_search_car .container .bravo-list-item,\r\n.bravo_search_event .container .bravo-list-item,\r\n.bravo_search_flight .container .bravo-list-item,\r\n.bravo_search_boat .container .bravo-list-item {\r\n    padding-top: 5%;\r\n}\r\n.bravo_search_hotel .container .bravo_filter, \r\n.bravo_search_space .container .bravo_filter,\r\n.bravo_search_tour .container .bravo_filter,\r\n.bravo_search_car .container .bravo_filter,\r\n.bravo_search_event .container .bravo_filter,\r\n.bravo_search_flight .container .bravo_filter,\r\n.bravo_search_boat .container .bravo_filter {\r\n    margin-top: 17%;\r\n}\r\n.bravo_wrap .bravo_banner {\r\n    padding: 190px 0 !important;\r\n}\r\n\r\n.form-search-rooms .g-button-submit .btn-search {\r\n    width: 200pc;\r\n    font-size: 13px;\r\n    height: 46px;\r\n}\r\n.form-search-rooms .g-button-submit {\r\n    display: flex;\r\n    align-items: center;\r\n}\r\n\r\n.bravo_detail_hotel .bravo_banner, \r\n.bravo_detail_tour .bravo_banner,\r\n.bravo_detail_space .bravo_banner,\r\n.bravo_detail_car .bravo_banner,\r\n.bravo_detail_boat .bravo_banner,\r\n.bravo_detail_event .bravo_banner,\r\n.bravo_detail_flight .bravo_banner {\r\n    height: 0;\r\n}\r\n\r\n.sale_info {\r\n    font-weight: 900 !important;\r\n    background: #000000 !important;\r\n    font-size: 10px !important;\r\n}\r\n\r\n.bravo-list-news, .bravo-list-vendor {\r\n    padding-top: 7%;\r\n}\r\n.header-adventages {\r\n    font-weight: 600;\r\n    font-size: 1.5rem;\r\n}\r\n.desc-adventages {\r\n    font-size: 1rem;\r\n}\r\n\r\n.list-adventages {\r\n    padding-left: 2%;\r\n}\r\n.img-adventages-header {\r\n        margin-bottom: 88px;\r\n    /* top: 0; */\r\n    /* background-image: url(https://virtuard.webgoster.com/uploads/0000/9/2023/07/27/pexels-pixabay-219692.jpg) !important; */\r\n    content: url(https://virtuard.webgoster.com/uploads/0000/9/2023/07/27/pexels-pixabay-219692.jpg);\r\n    /* height: 230px; */\r\n    width: 100%;\r\n    background-size: cover !important;\r\n}\r\n.bravo-list-vendor.story-vendor .list-item.story-vendor .item {\r\n    padding: 0 !important;\r\n    border: 0 !important;\r\n    margin-right: 1% !important;\r\n}', NULL, 11, 11, NULL, '2023-07-20 01:35:32', '2023-11-14 23:11:05'),
