(24, 1, 'en', 'Home Page', '[{\"type\":\"vendor_list_story\",\"name\":\"List Vendor Story\",\"model\":{\"title\":\"\",\"desc\":\"\",\"number\":\"\",\"order\":\"\",\"order_by\":\"\",\"custom_ids\":\"\"},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false},{\"type\":\"form_search_all_service\",\"name\":\"Form Search All Service\",\"model\":{\"service_types\":[\"hotel\",\"space\",\"tour\",\"car\",\"event\",\"flight\",\"boat\"],\"title\":\"Virtuard Your Virtual Tours.\",\"sub_title\":\"\",\"bg_image\":230,\"style\":\"\",\"list_slider\":[],\"title_for_hotel\":\"Business\",\"title_for_space\":\"Property\",\"title_for_car\":\"Accomodation\",\"title_for_event\":\"Cultural Haritage and Public Works\",\"title_for_tour\":\"Natural and Landscapes\",\"title_for_flight\":\"Rendering and Art\",\"title_for_boat\":\"Vehicles\",\"hide_form_search\":\"\"},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false},{\"type\":\"list_locations\",\"name\":\"List Locations\",\"model\":{\"service_type\":[\"space\",\"hotel\",\"tour\"],\"title\":\"Our Choice\",\"desc\":\"These popular destinations have a lot to offer\",\"number\":6,\"layout\":\"style_4\",\"order\":\"id\",\"order_by\":\"asc\",\"to_location_detail\":true,\"custom_ids\":[]},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false},{\"type\":\"list_hotel\",\"name\":\"Hotel: List Items\",\"model\":{\"title\":\"Recommended\",\"desc\":\"Recommended for your stay\",\"number\":8,\"style\":\"carousel\",\"location_id\":\"\",\"order\":\"id\",\"order_by\":\"asc\",\"is_featured\":false,\"custom_ids\":\"\"},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false},{\"type\":\"call_to_action\",\"name\":\"Call To Action\",\"model\":{\"title\":\"Request a virtual overview for your business, we can cover the whole world.\",\"sub_title\":\"\",\"link_title\":\"Contact us\",\"link_more\":\"mailto:info@virtuard.com\",\"style\":\"\",\"bg_color\":\"#000000\",\"bg_image\":\"\"},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false},{\"type\":\"testimonial\",\"name\":\"List Testimonial\",\"model\":{\"title\":\"Tertimonial\",\"list_item\":[{\"_active\":true,\"name\":\"Testimony 1\",\"desc\":\"Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book.\",\"number_star\":10,\"avatar\":null}]},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false},{\"type\":\"list_tours\",\"name\":\"Tour: List Items\",\"model\":{\"title\":\"Popular Destinations\",\"desc\":\"These popular destinations have a lot to offer\",\"number\":8,\"style\":\"carousel\",\"category_id\":\"\",\"location_id\":\"\",\"order\":\"id\",\"order_by\":\"desc\",\"is_featured\":false,\"custom_ids\":\"\"},\"component\":\"RegularBlock\",\"open\":true,\"is_container\":false}]', 11, NULL, '2023-11-07 13:44:59', '2023-11-07 13:44:59');
